    fun spec(network: String?): Spec? = network?.lowercase()?.let { specs[it] }

    /** ImageVector on a square viewport, glyph centered, filled [color]. */
    fun vector(spec: Spec, color: Color): ImageVector {
        val side = maxOf(spec.w, spec.h)
        val nodes = PathParser().parsePathString(spec.path).toNodes()
        return ImageVector.Builder(
            defaultWidth = 24.dp, defaultHeight = 24.dp,
            viewportWidth = side, viewportHeight = side,
        ).apply {
            addGroup(translationX = (side - spec.w) / 2f, translationY = (side - spec.h) / 2f)
            addPath(pathData = nodes, fill = SolidColor(color))
            clearGroup()
        }.build()
    }
}

/**
 * Bottom-right avatar badge: brand glyph in brand colour on a small chip with
 * the pane background — the native twin of the SPA's `absolute -bottom-1
 * -right-1 rounded-full bg-surface-0 border` badge. It OVERHANGS the avatar
 * (rendered outside its circle clip) instead of being masked by it. Renders
 * nothing for unknown networks.
 */
@Composable
fun NetworkBadge(network: String?, size: Dp = 17.dp, modifier: Modifier = Modifier) {
    val spec = NetworkIcons.spec(network) ?: return
    val vector = remember(network) { NetworkIcons.vector(spec, spec.brand) }
    Box(
        modifier
            .size(size)
            .clip(CircleShape)
            .background(MaterialTheme.colorScheme.surface),
        contentAlignment = Alignment.Center,
    ) {
        androidx.compose.material3.Icon(
            imageVector = vector,
            contentDescription = network,
            tint = Color.Unspecified,
            modifier = Modifier.size(size - 6.dp),
        )
    }
}
